SELECT count(*) FROM movie_companies, company_type, title, company_name, cast_info, char_name, role_type, name WHERE movie_companies.company_type_id = company_type.id AND movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.role_id = role_type.id AND cast_info.person_id = name.id;